from langchain.document_loaders import (
    PyPDFLoader,
    TextLoader,
    UnstructuredMarkdownLoader,
    UnstructuredHTMLLoader,
    CSVLoader
)
import os

def load_documents(directory: str) -> list:
    """Load documents from directory supporting multiple formats"""
    documents = []

    loaders = {
        '.pdf': PyPDFLoader,
        '.txt': TextLoader,
        '.md': UnstructuredMarkdownLoader,
        '.html': UnstructuredHTMLLoader,
        '.csv': CSVLoader
    }

    for root, dirs, files in os.walk(directory):
        for file in files:
            file_path = os.path.join(root, file)
            ext = os.path.splitext(file)[1].lower()

            if ext in loaders:
                try:
                    loader = loaders[ext](file_path)
                    docs = loader.load()

                    # Enrich metadata
                    for doc in docs:
                        doc.metadata.update({
                            'source': file_path,
                            'file_type': ext,
                            'file_name': file
                        })

                    documents.extend(docs)
                except Exception as e:
                    print(f"Error loading {file_path}: {e}")

    return documents

from langchain.text_splitter import Language, RecursiveCharacterTextSplitter
def chunk_code_documents(documents: list, language: str = "python") -> list: """Chunk code documents preserving structure"""
# Map language to splitter language_map = { "python": Language.PYTHON, "javascript": Language.JS, "typescript": Language.TS, "java": Language.JAVA, "cpp": Language.CPP }
splitter = RecursiveCharacterTextSplitter.from_language( language=language_map.get(language, Language.PYTHON), chunk_size=1000, # Larger for code chunk_overlap=100 )
chunks = splitter.split_documents(documents)
# Add code-specific metadata for chunk in chunks: chunk.metadata['content_type'] = 'code' chunk.metadata['language'] = language
# Extract function/class names if language == "python": chunk.metadata['functions'] = extract_python_functions(chunk.page_content) chunk.metadata['classes'] = extract_python_classes(chunk.page_content)
return chunks
def extract_python_functions(code: str) -> list: """Extract function names from Python code""" import re pattern = r'def\s+([a-zA-Z_][a-zA-Z0-9_]*)\s*\(' return re.findall(pattern, code)
def extract_python_classes(code: str) -> list: """Extract class names from Python code""" import re pattern = r'class\s+([a-zA-Z_][a-zA-Z0-9_]*)\s*[:\(]' return re.findall(pattern, code)


from opensearchpy import OpenSearch
from ibm_watsonx_ai import Embeddings
from ibm_watsonx_ai.foundation_models.utils.enums import EmbeddingTypes

class OpenSearchRAGStore:
    def __init__(self, index_name: str):
        self.index_name = index_name

        # Connect to OpenSearch
        self.client = OpenSearch(
            hosts=[{
                'host': os.getenv('OPENSEARCH_HOST'),
                'port': int(os.getenv('OPENSEARCH_PORT', 9200))
            }],
            http_auth=(
                os.getenv('OPENSEARCH_USER'),
                os.getenv('OPENSEARCH_PASSWORD')
            ),
            use_ssl=True,
            verify_certs=True
        )

        # Initialize IBM Watsonx embeddings
        self.embeddings = Embeddings(
            model_id=EmbeddingTypes.IBM_SLATE_125M_ENG,
            credentials={
                "url": os.getenv("WATSONX_URL"),
                "apikey": os.getenv("WATSONX_API_KEY")
            },
            project_id=os.getenv("WATSONX_PROJECT_ID")
        )

        # Create index
        self._create_index()

    def _create_index(self):
        """Create OpenSearch index with k-NN"""
        index_body = {
            "settings": {
                "index": {
                    "knn": True,
                    "knn.algo_param.ef_search": 100
                }
            },
            "mappings": {
                "properties": {
                    "embedding": {
                        "type": "knn_vector",
                        "dimension": 768,
                        "method": {
                            "name": "hnsw",
                            "space_type": "cosinesimil",
                            "engine": "nmslib",
                            "parameters": {
                                "ef_construction": 128,
                                "m": 16
                            }
                        }
                    },
                    "text": {"type": "text"},
                    "source": {"type": "keyword"},
                    "metadata": {"type": "object", "enabled": True}
                }
            }
        }

        if not self.client.indices.exists(self.index_name):
            self.client.indices.create(self.index_name, body=index_body)

    def add_documents(self, documents: list):
        """Add documents to index"""
        texts = [doc.page_content for doc in documents]

        # Generate embeddings with IBM Watsonx
        vectors = self.embeddings.embed_documents(texts, batch_size=100)

        # Bulk index
        bulk_data = []
        for doc, vector in zip(documents, vectors):
            bulk_data.append({
                "index": {"_index": self.index_name}
            })
            bulk_data.append({
                "embedding": vector,
                "text": doc.page_content,
                "source": doc.metadata.get('source', ''),
                "metadata": doc.metadata
            })

        self.client.bulk(body=bulk_data)
        self.client.indices.refresh(index=self.index_name)

    def hybrid_search(self, query: str, top_k: int = 10, keyword_weight: float = 0.3):
        """Hybrid search combining k-NN and BM25"""
        query_vector = self.embeddings.embed_query(query)

        search_body = {
            "size": top_k,
            "query": {
                "bool": {
                    "should": [
                        {
                            "knn": {
                                "embedding": {
                                    "vector": query_vector,
                                    "k": top_k
                                }
                            }
                        },
                        {
                            "match": {
                                "text": {
                                    "query": query,
                                    "boost": keyword_weight
                                }
                            }
                        }
                    ]
                }
            }
        }

        results = self.client.search(index=self.index_name, body=search_body)

        return [
            {
                "text": hit['_source']['text'],
                "source": hit['_source']['source'],
                "metadata": hit['_source']['metadata'],
                "score": hit['_score']
            }
            for hit in results['hits']['hits']
        ]


class ConversationalRAG:
    def __init__(self, vector_store, llm):
        self.vector_store = vector_store
        self.llm = llm
        self.conversation_history = []

    def chat(self, user_message: str, top_k: int = 5):
        """Chat with conversation history"""
        # Rewrite query considering history
        rewritten_query = self._rewrite_query(user_message)

        # Retrieve relevant documents
        results = self.vector_store.search(rewritten_query, top_k=top_k)

        # Format context
        context = "\n\n".join([doc['text'] for doc in results])

        # Build prompt with history
        history_text = "\n".join([
            f"User: {turn['user']}\nAssistant: {turn['assistant']}"
            for turn in self.conversation_history[-3:]  # Last 3 turns
        ])

        prompt = f"""
Previous conversation:
{history_text}

Context:
{context}

Current question: {user_message}

Answer the current question using the context and conversation history.

Answer:
"""

        answer = self.llm.generate_text(prompt)

        # Update history
        self.conversation_history.append({
            "user": user_message,
            "assistant": answer
        })

        return {
            "answer": answer,
            "sources": [doc['source'] for doc in results]
        }

    def _rewrite_query(self, query: str) -> str:
        """Rewrite query considering conversation history"""
        if not self.conversation_history:
            return query

        history_text = "\n".join([
            f"User: {turn['user']}\nAssistant: {turn['assistant']}"
            for turn in self.conversation_history[-2:]
        ])

        rewrite_prompt = f"""
Given the conversation history, rewrite the current query to be standalone.

Conversation history:
{history_text}

Current query: {query}

Rewritten standalone query:
"""

        rewritten = self.llm.generate_text(rewrite_prompt, max_new_tokens=100)
        return rewritten.strip()

    def clear_history(self):
        """Clear conversation history"""
        self.conversation_history = []

from fastmcp import FastMCP from typing import Optional, List
mcp = FastMCP("RAG Retrieval Server")
# Global RAG pipeline instance rag_pipeline = None
def get_rag_pipeline(): """Get or create RAG pipeline instance""" global rag_pipeline if rag_pipeline is None: vector_store = MilvusRAGStore( collection_name=os.getenv("COLLECTION_NAME", "knowledge_base") ) rag_pipeline = RAGPipeline(vector_store) return rag_pipeline
@mcp.tool() def search_knowledge_base( query: str, top_k: int = 5, filters: Optional[dict] = None ) -> List[dict]: """ Search the RAG knowledge base for relevant documents.
Args: query: Search query top_k: Number of results to return (default: 5) filters: Optional metadata filters
Returns: List of relevant documents with scores """ try: pipeline = get_rag_pipeline()
# Build filter expression filter_expr = None if filters: filter_expr = " AND ".join([ f"{key} == '{value}'" for key, value in filters.items() ])
results = pipeline.vector_store.search( query, top_k=top_k, filter_expr=filter_expr )
return [ { "text": hit.entity.get('text'), "source": hit.entity.get('source'), "metadata": hit.entity.get('metadata'), "score": hit.score } for hit in results ] except Exception as e: return [{"error": str(e)}]
@mcp.tool() def ask_question( question: str, top_k: int = 5, include_sources: bool = True ) -> dict: """ Ask a question using RAG with IBM Watsonx.
Args: question: Question to answer top_k: Number of documents to retrieve (default: 5) include_sources: Whether to include source citations (default: True)
Returns: Dictionary with answer and optional sources """ try: pipeline = get_rag_pipeline() response = pipeline.query(question, top_k, include_sources) return response except Exception as e: return {"error": str(e)}
@mcp.tool() def start_conversation() -> dict: """ Start a new conversational RAG session.
Returns: Session information """ try: pipeline = get_rag_pipeline()
# Create conversational RAG conv_rag = ConversationalRAG( pipeline.vector_store, pipeline.llm )
# Store in session (simplified - use proper session management) return { "session_id": "new_session", "status": "ready", "message": "Conversational RAG session started" } except Exception as e: return {"error": str(e)}
@mcp.tool() def chat( message: str, session_id: str = "default", top_k: int = 5 ) -> dict: """ Chat with the RAG system maintaining conversation history.
Args: message: User message session_id: Conversation session ID top_k: Number of documents to retrieve
Returns: Response with answer and sources """ try: # Get conversational RAG (simplified - use proper session management) pipeline = get_rag_pipeline() conv_rag = ConversationalRAG(pipeline.vector_store, pipeline.llm)
response = conv_rag.chat(message, top_k) return response except Exception as e: return {"error": str(e)}

def multi_query_retrieval(query: str, vector_store, llm, top_k: int = 5): """Retrieve using multiple query variations"""
# Generate query variations variation_prompt = f""" Generate 3 different versions of this question that could help find relevant information:
Original question: {query}
Variations: 1. 2. 3. """
variations_text = llm.generate_text(variation_prompt, max_new_tokens=200)
# Parse variations variations = [query] # Include original for line in variations_text.split('\n'): if line.strip() and not line.startswith('Variations:'): clean_line = line.strip().lstrip('123.').strip() if clean_line: variations.append(clean_line)
# Search with all variations all_results = [] seen_ids = set()
for var in variations: results = vector_store.search(var, top_k=top_k)
for doc in results: doc_id = doc.get('metadata', {}).get('chunk_id') if doc_id not in seen_ids: all_results.append(doc) seen_ids.add(doc_id)
# Sort by score and return top_k all_results.sort(key=lambda x: x.get('score', 0), reverse=True) return all_results[:top_k]
